const CLASS_SEEDS: Record<string, number> = { warrior: 0xca1101, rogue: 0xca1102, sorcerer: 0xca1103 }
export function generateStartingItems(classId: string): Item[] {
  const rng = makeRng(CLASS_SEEDS[classId] ?? 0xca1100)
  const items: Item[] = []
  if (classId === 'warrior' || classId === 'sorcerer') {
    items.push(generateItem(rng, 1, { quality: 'magic', slot: 'weapon', forceBaseId: 'short_sword' }))
  } else if (classId === 'rogue') {
    items.push(generateItem(rng, 1, { quality: 'magic', slot: 'weapon', forceBaseId: 'dagger' }))
  }
  // potions...
  return items
}

const isFirstClassRun = classId && !classesPlayed.includes(classId)
// after set():
if (isFirstClassRun && classId) {
  const items = generateStartingItems(classId)
  const inv = useInventoryStore.getState()
  for (const item of items) inv.addItem(item)
}
